#include "unitcheck.h"

#include "curl.h"

static CURLcode test_h3_priority_parsing(const char *arg)
{
  UNITTEST_BEGIN_SIMPLE

  (void)arg;

#ifdef USE_HTTP3
  CURL *curl;
  CURLcode res = CURLE_OK;

  curl = curl_easy_init();
  if(!curl) {
    UNITTEST_ERROR("Failed to init curl");
    return CURLE_OUT_OF_MEMORY;
  }

  /* Test valid priority format: u=3 */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=3");
  if(res != CURLE_OK) {
    UNITTEST_ERROR("Failed to set basic urgency");
    curl_easy_cleanup(curl);
    return res;
  }

  /* Test valid priority format with incremental: u=5,i */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=5,i");
  if(res != CURLE_OK) {
    UNITTEST_ERROR("Failed to set urgency with incremental flag");
    curl_easy_cleanup(curl);
    return res;
  }

  /* Test edge case: u=0 (highest priority) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  if(res != CURLE_OK) {
    UNITTEST_ERROR("Failed to set u=0");
    curl_easy_cleanup(curl);
    return res;
  }

  /* Test edge case: u=7 (lowest priority) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  if(res != CURLE_OK) {
    UNITTEST_ERROR("Failed to set u=7");
    curl_easy_cleanup(curl);
    return res;
  }

  /* Test invalid format: out of range urgency */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=8");
  if(res == CURLE_OK) {
    UNITTEST_ERROR("Should have rejected u=8");
    curl_easy_cleanup(curl);
    return CURLE_FAILED_INIT;
  }

  /* Test invalid format: missing u= */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "3");
  if(res == CURLE_OK) {
    UNITTEST_ERROR("Should have rejected format without u=");
    curl_easy_cleanup(curl);
    return CURLE_FAILED_INIT;
  }

  curl_easy_cleanup(curl);

#endif

  UNITTEST_END_SIMPLE
}

DECLARE_TEST_UNIT(unit_h3_priority_parsing);

